function rgb(hex) {
  const h = hex.replace('#','');
  return { r: parseInt(h.slice(0,2),16)/255, g: parseInt(h.slice(2,4),16)/255, b: parseInt(h.slice(4,6),16)/255 };
}
function solid(hex, opacity=1) { return { type:'SOLID', color:rgb(hex), opacity }; }
function shadow(color='#0F294A', opacity=.10, y=12, blur=28) {
  return [{ type:'DROP_SHADOW', color:{...rgb(color), a:opacity}, offset:{x:0,y}, radius:blur, spread:0, visible:true, blendMode:'NORMAL' }];
}
function setStroke(node, hex, weight=1, opacity=1) {
  node.strokes=[solid(hex,opacity)]; node.strokeWeight=weight;
}
function rect(parent, name, x,y,w,h, fill, radius=0, effects=null) {
  const n=figma.createRectangle(); n.name=name; n.x=x; n.y=y; n.resize(w,h); n.fills=[fill]; n.cornerRadius=radius;
  if(effects) n.effects=effects; parent.appendChild(n); return n;
}
function frame(parent, name, x,y,w,h, fill=null, radius=0) {
  const n=figma.createFrame(); n.name=name; n.x=x; n.y=y; n.resize(w,h); n.clipsContent=false;
  n.fills=fill ? [fill] : []; n.cornerRadius=radius; parent.appendChild(n); return n;
}
function ellipse(parent,name,x,y,w,h,fill,stroke=null) {
  const n=figma.createEllipse(); n.name=name; n.x=x; n.y=y; n.resize(w,h); n.fills=[fill]; if(stroke) setStroke(n,stroke,1); parent.appendChild(n); return n;
}
async function pickFonts(){
  const pairs=[
    [{family:'Cairo',style:'Regular'},{family:'Cairo',style:'Bold'}],
    [{family:'Noto Sans Arabic',style:'Regular'},{family:'Noto Sans Arabic',style:'Bold'}],
    [{family:'Arial',style:'Regular'},{family:'Arial',style:'Bold'}],
    [{family:'Inter',style:'Regular'},{family:'Inter',style:'Bold'}]
  ];
  for(const [regular,bold] of pairs){
    try { await figma.loadFontAsync(regular); await figma.loadFontAsync(bold); return {regular,bold}; } catch(e) {}
  }
  throw new Error('تعذر تحميل خط يدعم العربية');
}
function addText(parent, name, content, x,y,w,size,color,font, opts={}) {
  const t=figma.createText(); t.name=name; t.fontName=font; t.characters=content; t.fontSize=size;
  t.fills=[solid(color)]; t.textAlignHorizontal=opts.align || 'RIGHT'; t.textAlignVertical='TOP';
  t.textAutoResize='HEIGHT'; t.resize(w, 10); t.x=x; t.y=y;
  if(opts.lineHeight) t.lineHeight={unit:'PIXELS', value:opts.lineHeight};
  if(opts.letterSpacing) t.letterSpacing={unit:'PIXELS', value:opts.letterSpacing};
  parent.appendChild(t); return t;
}
function svgIcon(parent,name,svg,x,y,size,color){
  const markup=`<svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" stroke="${color}" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">${svg}</svg>`;
  const n=figma.createNodeFromSvg(markup); n.name=name; n.x=x; n.y=y; n.resize(size,size); parent.appendChild(n); return n;
}
function base64ToBytes(s){
  const chars='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/='; let str=s.replace(/=+$/,''); let out=[]; let bc=0, bs, buffer, idx=0;
  for(; (buffer=str.charAt(idx++)); ~buffer && (bs=bc%4?bs*64+buffer:buffer, bc++%4) ? out.push(255 & bs >> (-2*bc & 6)) : 0) buffer=chars.indexOf(buffer);
  return new Uint8Array(out);
}

