function addHero(screen, fonts, logoHash){
  const hero=frame(screen,'Hero / Header',0,0,430,230,solid(C.navy900),0); hero.clipsContent=true;
  hero.fills=[{type:'GRADIENT_LINEAR', gradientStops:[{position:0,color:{...rgb(C.navy950),a:1}},{position:.58,color:{...rgb(C.navy900),a:1}},{position:1,color:{...rgb(C.navy800),a:1}}], gradientTransform:[[1,0,0],[0,1,0]]}];
  for(let i=0;i<8;i++) ellipse(hero,'Tech Dot '+(i+1),24+i*48,112+(i%2)*18,3,3,solid(C.teal500,.24));
  for(let r=0;r<4;r++){ const e=ellipse(hero,'Tech Ring '+(r+1),-145-r*22,58-r*22,300+r*44,300+r*44,solid('#FFFFFF',0),null); e.strokes=[solid(C.teal500,.10)]; e.strokeWeight=1; }
  const avatar=rect(hero,'Avatar',348,18,48,48,solid(C.teal600),17,shadow('#00162B',.28,10,22)); setStroke(avatar,'#FFFFFF',2,.55);
  svgIcon(hero,'Avatar Icon',ICONS.user,358,28,28,'#FFFFFF');
  addText(hero,'User Name','محمد الكناني',208,19,130,15,'#FFFFFF',fonts.bold,{lineHeight:23});
  addText(hero,'User Role','لوحة إدارة المدرسة',218,46,120,10,'#C7D5E4',fonts.regular,{lineHeight:16});
  const notify=rect(hero,'Notification Button',25,20,42,42,solid('#FFFFFF',.08),15); setStroke(notify,'#FFFFFF',1,.18); svgIcon(hero,'Notification Icon',ICONS.bell,35,30,22,'#FFFFFF'); ellipse(hero,'Notification Dot',52,25,9,9,solid('#43D4D6')); setStroke(hero.children[hero.children.length-1],'#0A315A',2,1);
  addText(hero,'Hero Title','إدارة مدرسية\nأكثر ذكاءً',174,96,222,27,'#FFFFFF',fonts.bold,{lineHeight:37});
  addText(hero,'Hero Subtitle','الجداول والمتابعة في تجربة واحدة واضحة',143,174,253,11,'#C7D5E4',fonts.regular,{lineHeight:18});
  const logoCard=rect(hero,'Logo Card',25,102,92,92,solid('#FFFFFF',.98),24,shadow('#00162B',.26,15,30));
  const logo=rect(hero,'Smart Table Logo',35,112,72,72,solid('#FFFFFF',0),0); logo.fills=[{type:'IMAGE',scaleMode:'FIT',imageHash:logoHash}];
}

function modeSwitcher(screen, fonts, active){
  const sw=frame(screen,'Mode Switcher',17,206,396,68,solid('#FFFFFF',.98),22); sw.effects=shadow('#0F294A',.10,12,28); setStroke(sw,'#FFFFFF',1,.95);
  const smartActive=active==='smart', adminActive=active==='admin';
  function tab(name,x,label,icon,isActive,smart){
    const f=frame(sw,name,x,6,190,56,isActive?solid(smart?C.teal600:C.navy900):solid('#FFFFFF',0),17); if(isActive) f.effects=shadow(smart?C.teal700:C.navy900,.22,10,20);
    svgIcon(f,name+' Icon',icon,151,17,22,isActive?'#FFFFFF':'#607087');
    addText(f,name+' Label',label,22,17,119,13,isActive?'#FFFFFF':'#607087',fonts.bold,{align:'RIGHT',lineHeight:22});
  }
  tab('Smart Tab',200,'الجدول الذكي',ICONS.calendar,smartActive,true);
  tab('Admin Tab',6,'المتابع الإداري',ICONS.admin,adminActive,false);
}

