function toolCard(screen, fonts, item, y){
  const c=frame(screen,'Tool Card / '+item.title,17,y,396,72,solid('#FFFFFF',.98),20); c.effects=shadow('#173253',.075,7,18); setStroke(c,'#E2E9F2',1,.95);
  rect(c,'Accent',392,0,4,72,solid(item.accent),0);
  const ib=rect(c,'Icon Background',324,9,54,54,solid(item.bg),18); setStroke(ib,'#FFFFFF',1,.8); svgIcon(c,'Icon / '+item.title,item.icon,337,22,28,item.accent);
  addText(c,'Title / '+item.title,item.title,94,12,214,14,C.ink,fonts.bold,{lineHeight:23});
  addText(c,'Description / '+item.title,item.desc,94,38,214,9.7,C.muted,fonts.regular,{lineHeight:16});
  const ch=rect(c,'Chevron Background',14,22,28,28,solid('#F3F6FA'),10); svgIcon(c,'Chevron',ICONS.chevron,20,28,16,'#91A0B3');
}

